import React, { useState } from "react";
import Register from "./components/Register";
import Login from "./components/Login";
import KycFormEnhanced from "./components/KycFormEnhanced";
import DashboardEnhanced from "./components/DashboardEnhanced";
import AdminKycPanel from "./components/AdminKycPanel";
import DatabaseViewer from "./components/DatabaseViewer";

function App() {
  const [username, setUsername] = useState("");
  const [role, setRole] = useState("USER");
  const [loggedIn, setLoggedIn] = useState(false);
  const [kycStatus, setKycStatus] = useState("PENDING");
  const [showDbViewer, setShowDbViewer] = useState(false);

  const handleLoginSuccess = (user, userRole, kycStatus) => {
    setUsername(user);
    setRole(userRole || "USER");
    setKycStatus(kycStatus || "PENDING");
    setLoggedIn(true);
  };

  const handleKycSubmit = (user, userRole) => {
    setUsername(user);
    setRole(userRole || "USER");
    setKycStatus("SUBMITTED");
    setLoggedIn(true);
  };

  const handleKycApproved = () => {
    setKycStatus("APPROVED");
  };

  if (!loggedIn) {
    return (
      <div className="auth-container">
        <div className="auth-header">
          <h1 className="bank-title">🏦 Secure Bank</h1>
          <p className="bank-subtitle">Your Trusted Digital Banking Partner</p>
        </div>
        <div className="auth-panels">
          <Register />
          <Login onSuccess={handleLoginSuccess} />
        </div>
      </div>
    );
  }

  // KYC Pending/Submitted - Show KYC form
  if (kycStatus === "PENDING" || kycStatus === "SUBMITTED") {
    return (
      <KycFormEnhanced 
        username={username} 
        onKycSubmit={handleKycSubmit}
        onKycApproved={handleKycApproved}
        currentStatus={kycStatus}
      />
    );
  }

  // Add database viewer option for admin
  if (role === "ADMIN") {
    if (showDbViewer) {
      return <DatabaseViewer username={username} onLogout={() => setLoggedIn(false)} />;
    }
    
    return (
      <div>
        <div style={{ padding: "10px", background: "#f8f9fa", borderBottom: "1px solid #ddd" }}>
          <button onClick={() => setShowDbViewer(!showDbViewer)} className="admin-toggle-btn">
            {showDbViewer ? "📋 KYC Panel" : "🗄️ Database Viewer"}
          </button>
        </div>
        <AdminKycPanel username={username} onLogout={() => setLoggedIn(false)} />
      </div>
    );
  }

  // Regular User Dashboard - Only if KYC is approved
  if (kycStatus === "APPROVED") {
    return <Dashboard username={username} onLogout={() => setLoggedIn(false)} />;
  }

  // KYC Approved - Show success message
  if (kycStatus === "APPROVED") {
    return (
      <div className="kyc-success-container">
        <div className="success-card">
          <div className="success-icon">✅</div>
          <h2>Account Created Successfully!</h2>
          <p>Your KYC has been approved and your account is now active.</p>
          <p>You can now access all banking features.</p>
          <button 
            onClick={() => setKycStatus("APPROVED")} 
            className="proceed-btn"
          >
            Proceed to Dashboard
          </button>
        </div>
      </div>
    );
  }

  return <Dashboard username={username} onLogout={() => setLoggedIn(false)} />;
}

export default App;
